1	/**
2	 * Normalizes different header inputs into a plain record with lower-case keys.
3	 * Entries with `undefined` or `null` values are removed.
4	 *
5	 * @param headers - Input headers (`Headers`, tuples array, plain record) to normalize.
6	 * @returns A record containing the normalized header entries.
7	 */
8	export function normalizeHeaders(
9	  headers:
10	    | HeadersInit
11	    | Record<string, string | undefined>
12	    | Array<[string, string | undefined]>
13	    | undefined,
14	): Record<string, string> {
15	  if (headers == null) {
16	    return {};
17	  }
18	
19	  const normalized: Record<string, string> = {};
20	
21	  if (headers instanceof Headers) {
22	    headers.forEach((value, key) => {
23	      normalized[key.toLowerCase()] = value;
24	    });
25	  } else {
26	    if (!Array.isArray(headers)) {
27	      headers = Object.entries(headers);
28	    }
29	
30	    for (const [key, value] of headers) {
31	      if (value != null) {
32	        normalized[key.toLowerCase()] = value;
33	      }
34	    }
35	  }
36	
37	  return normalized;
38	}
