3	/**
4	 * Loads a `string` setting from the environment or a parameter.
5	 *
6	 * @param settingValue - The setting value.
7	 * @param environmentVariableName - The environment variable name.
8	 * @param settingName - The setting name.
9	 * @param description - The description of the setting.
10	 * @returns The setting value.
11	 */
12	export function loadSetting({
13	  settingValue,
14	  environmentVariableName,
15	  settingName,
16	  description,
17	}: {
18	  settingValue: string | undefined;
19	  environmentVariableName: string;
20	  settingName: string;
21	  description: string;
22	}): string {
23	  if (typeof settingValue === 'string') {
24	    return settingValue;
25	  }
26	
27	  if (settingValue != null) {
28	    throw new LoadSettingError({
29	      message: `${description} setting must be a string.`,
30	    });
31	  }
32	
33	  if (typeof process === 'undefined') {
34	    throw new LoadSettingError({
35	      message:
36	        `${description} setting is missing. ` +
37	        `Pass it using the '${settingName}' parameter. ` +
38	        `Environment variables is not supported in this environment.`,
39	    });
40	  }
41	
42	  settingValue = process.env[environmentVariableName];
43	
44	  if (settingValue == null) {
45	    throw new LoadSettingError({
46	      message:
47	        `${description} setting is missing. ` +
48	        `Pass it using the '${settingName}' parameter ` +
49	        `or the ${environmentVariableName} environment variable.`,
50	    });
51	  }
52	
53	  if (typeof settingValue !== 'string') {
54	    throw new LoadSettingError({
55	      message:
56	        `${description} setting must be a string. ` +
57	        `The value of the ${environmentVariableName} environment variable is not a string.`,
58	    });
59	  }
60	
61	  return settingValue;
62	}
