27	 *   prompt: 'A cat',
28	 *   images: [blob1, blob2],
29	 * });
30	 * ```
31	 */
32	export function convertToFormData<T extends Record<string, unknown>>(
33	  input: T,
34	  options: { useArrayBrackets?: boolean } = {},
35	): FormData {
36	  const { useArrayBrackets = true } = options;
37	  const formData = new FormData();
38	
39	  for (const [key, value] of Object.entries(input)) {
40	    if (value == null) {
41	      continue;
42	    }
43	
44	    if (Array.isArray(value)) {
45	      if (value.length === 1) {
46	        formData.append(key, value[0] as string | Blob);
47	        continue;
48	      }
49	
50	      const arrayKey = useArrayBrackets ? `${key}[]` : key;
51	      for (const item of value) {
52	        formData.append(arrayKey, item as string | Blob);
53	      }
54	      continue;
55	    }
56	
57	    formData.append(key, value as string | Blob);
58	  }
59	
60	  return formData;
61	}
