```typescript
export type ImageModelV3 = {
  /**
   * Must be 'v3' for the current specification version.
   */
  readonly specificationVersion: 'v3';

  /**
   * Name of the provider for logging purposes (e.g., 'replicate', 'openai.image').
   */
  readonly provider: string;

  /**
   * Provider-specific model ID for logging purposes.
   */
  readonly modelId: string;

  /**
   * Limit of how many images can be generated in a single API call.
   * Can be: number (fixed limit), undefined (use global limit), or a function.
   */
  readonly maxImagesPerCall: number | undefined | GetMaxImagesPerCallFunction;

  /**
   * Main method to generate images.
   */
  doGenerate(options: ImageModelV3CallOptions): PromiseLike<{
    /**
     * Generated images as base64 encoded strings OR Uint8Array binary data.
     * Return without unnecessary conversion - if the API returns base64, keep it as-is.
     */
    images: Array<string> | Array<Uint8Array>;

    /**
     * Warnings for unsupported features (e.g., "aspectRatio not supported").
     */
    warnings: Array<SharedV3Warning>;

    /**
     * Provider-specific metadata passed through from provider to SDK.
     * Keyed by provider name with an 'images' array inside.
     *
     * Example:
     * {
     *   "myProvider": {
     *     "images": [
     *       { "revisedPrompt": "A dog in the rain", ... },
     *       { ... }
     *     ]
     *   }
     * }
     */
    providerMetadata?: ImageModelV3ProviderMetadata;

    /**
     * Response metadata for telemetry/debugging.
     */
    response: {
      timestamp: Date;
      modelId: string;
      headers: Record<string, string> | undefined;
    };

    /**
     * Optional token usage (if provider reports it).
     */
    usage?: ImageModelV3Usage;
  }>;
};
```

