import {
  ImageModelV3,
  NoSuchModelError,
  ProviderV3,
} from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import { loadApiKey, withUserAgentSuffix } from '@ai-sdk/provider-utils';
import { ReplicateImageModel } from './replicate-image-model';
import { ReplicateImageModelId } from './replicate-image-settings';
import { VERSION } from './version';

export interface ReplicateProviderSettings {
  /**
   * API token sent via Authorization header.
   * Defaults to REPLICATE_API_TOKEN environment variable.
   */
  apiToken?: string;

  /**
   * Base URL for API calls.
   * Default: https://api.replicate.com/v1
   */
  baseURL?: string;

  /**
   * Custom headers to include in requests.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation for middleware/testing.
   */
  fetch?: FetchFunction;
}

export interface ReplicateProvider extends ProviderV3 {
  /**
   * Creates a Replicate image generation model.
   */
  image(modelId: ReplicateImageModelId): ImageModelV3;

  /**
   * Alias for image().
   */
  imageModel(modelId: ReplicateImageModelId): ImageModelV3;
}

export function createReplicate(
  options: ReplicateProviderSettings = {},
): ReplicateProvider {
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiToken,
          environmentVariableName: 'REPLICATE_API_TOKEN',
          description: 'Replicate',
        })}`,
        ...options.headers,
      },
      `ai-sdk/replicate/${VERSION}`,
    );

  const createImageModel = (modelId: ReplicateImageModelId) =>
    new ReplicateImageModel(modelId, {
      provider: 'replicate',
      baseURL: options.baseURL ?? 'https://api.replicate.com/v1',
      headers: getHeaders(),
      fetch: options.fetch,
    });

  // For image-only providers, throw NoSuchModelError for unsupported model types
  const languageModel = (modelId: string) => {
    throw new NoSuchModelError({
      modelId,
      modelType: 'languageModel',
    });
  };

  const embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({
      modelId,
      modelType: 'embeddingModel',
    });
  };

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel,
    embeddingModel,
    textEmbeddingModel: embeddingModel,
  };
}

export const replicate = createReplicate();
