  imageModel(modelId: ReplicateImageModelId): ImageModelV3;
}

export function createReplicate(
  options: ReplicateProviderSettings = {},
): ReplicateProvider {
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiToken,
          environmentVariableName: 'REPLICATE_API_TOKEN',
          description: 'Replicate',
        })}`,
        ...options.headers,
      },
      `ai-sdk/replicate/${VERSION}`,
    );

  const createImageModel = (modelId: ReplicateImageModelId) =>
    new ReplicateImageModel(modelId, {
      provider: 'replicate',
      baseURL: options.baseURL ?? 'https://api.replicate.com/v1',
      headers: getHeaders(),
      fetch: options.fetch,
    });

  // For image-only providers, throw NoSuchModelError for unsupported model types
  const languageModel = (modelId: string) => {
    throw new NoSuchModelError({
      modelId,
      modelType: 'languageModel',
    });
  };

  const embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({
      modelId,
      modelType: 'embeddingModel',
    });
  };

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel,
    embeddingModel,
    textEmbeddingModel: embeddingModel,
  };
}

export const replicate = createReplicate();
```

